import{_ as l,o as s,c as n,ah as e,j as t,a as o}from"./chunks/framework.CkJUk41Q.js";const k=JSON.parse('{"title":"知识表示","description":"","frontmatter":{"title":"知识表示","order":4},"headers":[],"relativePath":"ai/symbol/representation.md","filePath":"ai/symbol/representation.md"}'),i={name:"ai/symbol/representation.md"},p={class:"MathJax",jax:"SVG",style:{direction:"ltr",position:"relative"}},r={style:{overflow:"visible","min-height":"1px","min-width":"1px","vertical-align":"-0.566ex"},xmlns:"http://www.w3.org/2000/svg",width:"4.844ex",height:"2.262ex",role:"img",focusable:"false",viewBox:"0 -750 2141 1000","aria-hidden":"true"},d={class:"MathJax",jax:"SVG",style:{direction:"ltr",position:"relative"}},T={style:{overflow:"visible","min-height":"1px","min-width":"1px","vertical-align":"-0.566ex"},xmlns:"http://www.w3.org/2000/svg",width:"4.618ex",height:"2.262ex",role:"img",focusable:"false",viewBox:"0 -750 2041 1000","aria-hidden":"true"};function h(c,a,m,u,Q,g){return s(),n("div",null,[a[7]||(a[7]=e(`<h1 id="知识表示" tabindex="-1">知识表示 <a class="header-anchor" href="#知识表示" aria-label="Permalink to “知识表示”">​</a></h1><p>知识表示解决的核心问题是：如何把人类的知识转化为计算机可以存储、检索和推理的形式。这是符号 AI 的工程基础——推理引擎再强大，没有良好的知识表示也只能在空集上推理。不同的表示方法在表达能力、推理效率、维护成本之间做出不同的权衡。</p><h2 id="产生式规则" tabindex="-1">产生式规则 <a class="header-anchor" href="#产生式规则" aria-label="Permalink to “产生式规则”">​</a></h2><p>产生式规则（Production Rule）是最直观的知识表示方法，形式为 <code>IF 条件 THEN 动作</code>。条件部分是一组关于当前事实的判断，动作部分可以是得出新结论、添加新事实或触发外部操作。MYCIN 系统就是用产生式规则编码医学知识，每条规则对应一条临床经验。</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>示例规则：</span></span>
<span class="line"><span>IF   发热 = true</span></span>
<span class="line"><span>AND  咳嗽 = true</span></span>
<span class="line"><span>AND  白细胞计数 &gt; 10000</span></span>
<span class="line"><span>THEN 感染类型 = 细菌性（置信度 0.8）</span></span></code></pre></div><p>产生式系统的工作循环包含三个阶段：匹配阶段扫描所有规则，找出条件部分被当前事实集满足的规则（称为冲突集）；冲突消解阶段从冲突集中选择一条规则执行，策略包括优先级排序、最近匹配优先、条件最特殊者优先等；执行阶段将选中规则的动作部分应用到事实集，可能添加新事实、修改已有事实或删除过期事实。这个&quot;匹配-选择-执行&quot;循环不断重复，直到没有新规则可以触发或达到终止条件。</p>`,6)),t("p",null,[a[4]||(a[4]=o("产生式规则的优势在于模块化：每条规则相对独立，添加新规则不需要修改已有规则。这在工程维护上是很大的优势。但劣势也很明显：规则之间实际上存在隐含的交互关系，添加新规则可能导致意想不到的推理路径；当规则数量达到数万条时，匹配阶段的扫描成本变得非常高昂，RETE 算法通过构建规则网络的增量匹配机制将匹配复杂度从 ",-1)),t("mjx-container",p,[(s(),n("svg",r,[...a[0]||(a[0]=[e('<g stroke="currentColor" fill="currentColor" stroke-width="0" transform="scale(1,-1)"><g data-mml-node="math"><g data-mml-node="mi"><path data-c="1D442" d="M740 435Q740 320 676 213T511 42T304 -22Q207 -22 138 35T51 201Q50 209 50 244Q50 346 98 438T227 601Q351 704 476 704Q514 704 524 703Q621 689 680 617T740 435ZM637 476Q637 565 591 615T476 665Q396 665 322 605Q242 542 200 428T157 216Q157 126 200 73T314 19Q404 19 485 98T608 313Q637 408 637 476Z" style="stroke-width:3;"></path></g><g data-mml-node="mo" transform="translate(763,0)"><path data-c="28" d="M94 250Q94 319 104 381T127 488T164 576T202 643T244 695T277 729T302 750H315H319Q333 750 333 741Q333 738 316 720T275 667T226 581T184 443T167 250T184 58T225 -81T274 -167T316 -220T333 -241Q333 -250 318 -250H315H302L274 -226Q180 -141 137 -14T94 250Z" style="stroke-width:3;"></path></g><g data-mml-node="mi" transform="translate(1152,0)"><path data-c="1D45B" d="M21 287Q22 293 24 303T36 341T56 388T89 425T135 442Q171 442 195 424T225 390T231 369Q231 367 232 367L243 378Q304 442 382 442Q436 442 469 415T503 336T465 179T427 52Q427 26 444 26Q450 26 453 27Q482 32 505 65T540 145Q542 153 560 153Q580 153 580 145Q580 144 576 130Q568 101 554 73T508 17T439 -10Q392 -10 371 17T350 73Q350 92 386 193T423 345Q423 404 379 404H374Q288 404 229 303L222 291L189 157Q156 26 151 16Q138 -11 108 -11Q95 -11 87 -5T76 7T74 17Q74 30 112 180T152 343Q153 348 153 366Q153 405 129 405Q91 405 66 305Q60 285 60 284Q58 278 41 278H27Q21 284 21 287Z" style="stroke-width:3;"></path></g><g data-mml-node="mo" transform="translate(1752,0)"><path data-c="29" d="M60 749L64 750Q69 750 74 750H86L114 726Q208 641 251 514T294 250Q294 182 284 119T261 12T224 -76T186 -143T145 -194T113 -227T90 -246Q87 -249 86 -250H74Q66 -250 63 -250T58 -247T55 -238Q56 -237 66 -225Q221 -64 221 250T66 725Q56 737 55 738Q55 746 60 749Z" style="stroke-width:3;"></path></g></g></g>',1)])])),a[1]||(a[1]=t("mjx-assistive-mml",{unselectable:"on",display:"inline",style:{top:"0px",left:"0px",clip:"rect(1px, 1px, 1px, 1px)","-webkit-touch-callout":"none","-webkit-user-select":"none","-khtml-user-select":"none","-moz-user-select":"none","-ms-user-select":"none","user-select":"none",position:"absolute",padding:"1px 0px 0px 0px",border:"0px",display:"block",width:"auto",overflow:"hidden"}},[t("math",{xmlns:"http://www.w3.org/1998/Math/MathML"},[t("mi",null,"O"),t("mo",{stretchy:"false"},"("),t("mi",null,"n"),t("mo",{stretchy:"false"},")")])],-1))]),a[5]||(a[5]=o(" 降低到接近 ",-1)),t("mjx-container",d,[(s(),n("svg",T,[...a[2]||(a[2]=[e('<g stroke="currentColor" fill="currentColor" stroke-width="0" transform="scale(1,-1)"><g data-mml-node="math"><g data-mml-node="mi"><path data-c="1D442" d="M740 435Q740 320 676 213T511 42T304 -22Q207 -22 138 35T51 201Q50 209 50 244Q50 346 98 438T227 601Q351 704 476 704Q514 704 524 703Q621 689 680 617T740 435ZM637 476Q637 565 591 615T476 665Q396 665 322 605Q242 542 200 428T157 216Q157 126 200 73T314 19Q404 19 485 98T608 313Q637 408 637 476Z" style="stroke-width:3;"></path></g><g data-mml-node="mo" transform="translate(763,0)"><path data-c="28" d="M94 250Q94 319 104 381T127 488T164 576T202 643T244 695T277 729T302 750H315H319Q333 750 333 741Q333 738 316 720T275 667T226 581T184 443T167 250T184 58T225 -81T274 -167T316 -220T333 -241Q333 -250 318 -250H315H302L274 -226Q180 -141 137 -14T94 250Z" style="stroke-width:3;"></path></g><g data-mml-node="mn" transform="translate(1152,0)"><path data-c="31" d="M213 578L200 573Q186 568 160 563T102 556H83V602H102Q149 604 189 617T245 641T273 663Q275 666 285 666Q294 666 302 660V361L303 61Q310 54 315 52T339 48T401 46H427V0H416Q395 3 257 3Q121 3 100 0H88V46H114Q136 46 152 46T177 47T193 50T201 52T207 57T213 61V578Z" style="stroke-width:3;"></path></g><g data-mml-node="mo" transform="translate(1652,0)"><path data-c="29" d="M60 749L64 750Q69 750 74 750H86L114 726Q208 641 251 514T294 250Q294 182 284 119T261 12T224 -76T186 -143T145 -194T113 -227T90 -246Q87 -249 86 -250H74Q66 -250 63 -250T58 -247T55 -238Q56 -237 66 -225Q221 -64 221 250T66 725Q56 737 55 738Q55 746 60 749Z" style="stroke-width:3;"></path></g></g></g>',1)])])),a[3]||(a[3]=t("mjx-assistive-mml",{unselectable:"on",display:"inline",style:{top:"0px",left:"0px",clip:"rect(1px, 1px, 1px, 1px)","-webkit-touch-callout":"none","-webkit-user-select":"none","-khtml-user-select":"none","-moz-user-select":"none","-ms-user-select":"none","user-select":"none",position:"absolute",padding:"1px 0px 0px 0px",border:"0px",display:"block",width:"auto",overflow:"hidden"}},[t("math",{xmlns:"http://www.w3.org/1998/Math/MathML"},[t("mi",null,"O"),t("mo",{stretchy:"false"},"("),t("mn",null,"1"),t("mo",{stretchy:"false"},")")])],-1))]),a[6]||(a[6]=o("，成为高性能产生式系统的标准实现。",-1))]),a[8]||(a[8]=e(`<h2 id="语义网络" tabindex="-1">语义网络 <a class="header-anchor" href="#语义网络" aria-label="Permalink to “语义网络”">​</a></h2><p>语义网络（Semantic Network）用图结构表示知识。节点表示概念（如&quot;鸟&quot;、&quot;动物&quot;、&quot;企鹅&quot;），边表示概念间的关系（如&quot;是一种&quot;、&quot;有属性&quot;、&quot;是部分&quot;）。继承机制是语义网络的核心推理方式：企鹅节点通过&quot;是一种&quot;边连接到鸟节点，自动继承鸟的所有属性，无需重复编码。</p><p>语义网络的表达能力主要体现在边的类型上。分类关系（IS-A）建立概念层次，支持继承推理；组成关系（PART-OF）描述部分与整体的关系；属性关系描述概念的特征值，如&quot;鸟-有属性-翅膀&quot;。这些关系类型使得语义网络能够自然地表示分类学知识和本体结构。 语义网络的主要问题是缺乏形式化的语义定义。早期的语义网络没有统一的标准来规定边的含义——同一条&quot;IS-A&quot;边在不同系统中可能表示不同的关系。这个缺陷导致推理结果可能存在歧义和矛盾。后来的描述逻辑和本体论标准（如 OWL）正是为了解决这个问题，给语义网络赋予了严格的数学基础。</p><h2 id="框架理论" tabindex="-1">框架理论 <a class="header-anchor" href="#框架理论" aria-label="Permalink to “框架理论”">​</a></h2><p>框架理论（Frame Theory）由 Marvin Minsky 在 1975 年提出，核心思想是用结构化的模板表示典型场景或概念。一个框架包含多个槽位（Slot），每个槽位有名称和值。比如&quot;餐厅&quot;框架可能有槽位：场景（室内）、座位（桌子+椅子）、服务员（有）、菜单（有）、付款方式（现金/刷卡）。</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>框架示例：餐厅就餐场景</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[餐厅]</span></span>
<span class="line"><span>  场景类型: 室内</span></span>
<span class="line"><span>  参与者: [顾客], [服务员]</span></span>
<span class="line"><span>  设施: [桌子], [椅子], [厨房]</span></span>
<span class="line"><span>  事件序列:</span></span>
<span class="line"><span>    1. 进入 → 找座位</span></span>
<span class="line"><span>    2. 点餐 → 等待</span></span>
<span class="line"><span>    3. 用餐</span></span>
<span class="line"><span>    4. 付款 → 离开</span></span>
<span class="line"><span></span></span>
<span class="line"><span>当实际情况偏离框架预设时，槽位可以填入异常值。</span></span>
<span class="line"><span>比如&quot;外卖&quot;场景中，&quot;座位&quot;槽位为空，&quot;付款&quot;先于&quot;用餐&quot;。</span></span></code></pre></div><p>框架理论的精妙之处在于默认值和异常处理机制。默认值表示典型情况下的期望值——餐厅通常有菜单，所以&quot;菜单&quot;槽位的默认值为&quot;有&quot;。当遇到特殊场景时，只需覆盖特定槽位的值，其他槽位自动继承默认值。这减少了知识编码的工作量，同时为处理非典型情况提供了结构化的框架。</p><p>框架与面向对象编程中的类有很强的对应关系：框架对应类，槽位对应属性，框架间的继承关系对应类的继承层次。这种对应并非巧合——面向对象范式的很多设计思想都可以追溯到框架理论对知识表示的探索。</p><h2 id="本体论与描述逻辑" tabindex="-1">本体论与描述逻辑 <a class="header-anchor" href="#本体论与描述逻辑" aria-label="Permalink to “本体论与描述逻辑”">​</a></h2><p>本体论（Ontology）在 AI 领域指对特定领域概念及其关系的明确定义。与语义网络不同，本体论使用严格的形式化语言定义概念的层次结构、属性约束和关系类型，消除了语义歧义。OWL（Web Ontology Language）是 W3C 制定的本体标准语言，支持定义类、属性、个体以及它们之间的复杂约束。</p><p>描述逻辑（Description Logic，DL）是 OWL 的数学基础，是一阶逻辑的可判定子集。描述逻辑的核心设计理念是在表达能力和推理复杂度之间取得精确的平衡。表达能力越强的描述逻辑，推理的计算复杂度越高。OWL 2 的不同子语言（OWL 2 EL、OWL 2 QL、OWL 2 RL）对应不同复杂度级别的描述逻辑，允许用户根据应用需求选择合适的表达力。</p><p>描述逻辑的基本构造块是概念（concept，对应类）和角色（role，对应属性）。复杂概念通过构造算子从简单概念组合而成。比如 <code>Person ⊓ ∃hasChild.Student</code> 表示&quot;有一个学生孩子的所有人&quot;，其中 ⊓ 是交集算子，∃ 是存在量词算子。推理任务包括概念可满足性（判断一个概念是否可能为空）、概念包含（判断一个概念是否是另一个的子集）、实例检查（判断一个个体是否属于某概念）等。</p><h2 id="知识图谱" tabindex="-1">知识图谱 <a class="header-anchor" href="#知识图谱" aria-label="Permalink to “知识图谱”">​</a></h2><p>知识图谱（Knowledge Graph）是语义网络和本体论在工业界的现代化实现。以 RDF 三元组（主语-谓词-宾语）为基本数据单元，比如 <code>(Einstein, birthPlace, Germany)</code> 表示&quot;爱因斯坦出生在德国&quot;。大规模知识图谱如 Wikidata、DBpedia 包含数十亿条三元组，覆盖了人类知识的广泛领域。</p><p>知识图谱与大语言模型的结合是当前 AI 工程的前沿方向。大模型通过参数记忆了大量世界知识，但存在幻觉问题——它可能以很高置信度生成错误的事实。知识图谱作为外部知识源可以为大模型提供事实校验，检索增强生成（RAG）技术本质上就是用知识图谱（或向量数据库）的检索结果约束大模型的生成范围。</p><p>Google 的 Knowledge Graph 从 2012 年开始在搜索结果中展示结构化知识面板，这标志着知识图谱从学术概念进入了大众视野。国内的百度、阿里也构建了自己的大规模知识图谱，用于智能搜索、推荐系统和智能问答。知识图谱的构建仍然是工程难题：从非结构化文本中抽取三元组需要高精度的命名实体识别和关系抽取模型，跨源知识融合需要解决实体对齐和冲突消解问题。</p><h2 id="表示方法的选择" tabindex="-1">表示方法的选择 <a class="header-anchor" href="#表示方法的选择" aria-label="Permalink to “表示方法的选择”">​</a></h2><p>不同的知识表示方法并非互相替代，而是适用于不同场景。产生式规则适合编码专家经验，在业务规则引擎中广泛使用；语义网络和本体论适合构建领域知识体系，在医疗、金融等领域用于标准化知识管理；框架理论适合表示场景化的知识，在自然语言理解中用于上下文建模；知识图谱适合大规模事实存储和检索，是现代智能系统的知识基础设施。</p><p>在实际工程中，往往需要组合多种表示方法。一个智能问答系统可能用知识图谱存储事实，用本体论定义概念层次，用产生式规则处理业务逻辑。理解各种表示方法的优劣和适用范围，是设计知识系统的基础能力。</p>`,19))])}const b=l(i,[["render",h]]);export{k as __pageData,b as default};
